import 'package:flutter/material.dart';
import 'package:get/get.dart';

void main() => runApp(MyApp());

// --- Domain Layer ---
class User {
  final String name;
  User(this.name);
}

abstract class IUserRepository {
  Future<User> login(String email, String password);
}

class LoginUseCase {
  final IUserRepository repository;
  LoginUseCase(this.repository);

  Future<User> execute(String email, String password) async {
    if (email.isEmpty || password.isEmpty) {
      throw Exception('Email and password required');
    }
    return await repository.login(email, password);
  }
}

// --- Data Layer ---
class FakeUserRepository implements IUserRepository {
  @override
  Future<User> login(String email, String password) async {
    await Future.delayed(Duration(seconds: 1));
    if (email == 'test@example.com' && password == '123') {
      return User('John Doe');
    } else {
      throw Exception('Invalid credentials');
    }
  }
}

// --- Presentation Layer ---
class LoginController extends GetxController {
  final LoginUseCase loginUseCase;
  LoginController(this.loginUseCase);

  var isLoading = false.obs;
  var error = ''.obs;

  Future<void> login(String email, String password) async {
    isLoading.value = true;
    error.value = '';
    try {
      final user = await loginUseCase.execute(email, password);
      Get.snackbar('Success', 'Welcome ${user.name}');
    } catch (e) {
      error.value = e.toString();
    } finally {
      isLoading.value = false;
    }
  }
}

// Binding
class LoginBinding extends Bindings {
  @override
  void dependencies() {
    Get.lazyPut<IUserRepository>(() => FakeUserRepository());
    Get.lazyPut(() => LoginUseCase(Get.find()));
    Get.lazyPut(() => LoginController(Get.find()));
  }
}

// Page
class LoginPage extends StatelessWidget {
  final controller = Get.find<LoginController>();
  final TextEditingController emailController = TextEditingController();
  final TextEditingController passwordController = TextEditingController();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Clean Architecture Demo')),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            TextField(controller: emailController, decoration: InputDecoration(labelText: 'Email')),
            TextField(controller: passwordController, decoration: InputDecoration(labelText: 'Password'), obscureText: true),
            SizedBox(height: 20),
            Obx(() => controller.isLoading.value
                ? CircularProgressIndicator()
                : ElevatedButton(
                    onPressed: () => controller.login(emailController.text, passwordController.text),
                    child: Text('Login'),
                  )),
            Obx(() => controller.error.isNotEmpty ? Text(controller.error, style: TextStyle(color: Colors.red)) : SizedBox.shrink()),
          ],
        ),
      ),
    );
  }
}

// App
class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return GetMaterialApp(
      initialRoute: '/login',
      getPages: [
        GetPage(name: '/login', page: () => LoginPage(), binding: LoginBinding()),
      ],
    );
  }
}
